INSERT INTO knowledge_card
(category, title, question, answer, follow_up, key_points, difficulty, tags, source_name, source_url, enabled, sort_order, created_at, updated_at)
VALUES
('JAVA', 'HashMap 在 JDK 1.8 中的底层结构', 'HashMap 在 JDK 1.8 中的底层结构是什么？', 'JDK 1.8 的 HashMap 底层是数组、链表和红黑树。数组负责按 hash 定位桶，链表处理哈希冲突；当同一桶链表长度达到 8 且数组容量达到 64 时，会转成红黑树，降低极端冲突下的查询成本。相比单纯链表结构，它能把最坏查询复杂度从 O(n) 优化到 O(log n)。', '为什么链表树化阈值是 8？\n为什么数组容量小于 64 时优先扩容而不是树化？\nJDK 1.8 为什么改成尾插法？', '数组 + 链表 + 红黑树\n链表长度达到 8 且数组长度达到 64 时树化\n极端冲突下查询从 O(n) 优化到 O(log n)\n尾插法避免 JDK 1.7 扩容并发下的链表环问题', 'EASY', 'Java集合,HashMap,数据结构', '小林 coding, JavaGuide', 'https://xiaolincoding.com/interview/', 1, 1, NOW(), NOW()),
('JAVA', 'ArrayList 和 LinkedList 的区别', 'ArrayList 和 LinkedList 有什么区别？', 'ArrayList 底层是动态数组，随机访问快，适合按下标读取和尾部追加；但中间插入删除需要移动元素。LinkedList 底层是双向链表，随机访问需要遍历，定位成本高；在已经拿到节点位置时插入删除更方便，但每个节点有额外指针开销。实际开发中 ArrayList 更常用，因为遍历和缓存局部性通常更好。', '为什么实际业务里 ArrayList 通常比 LinkedList 更常用？\nArrayList 扩容大致怎么做？\nLinkedList 插入删除一定比 ArrayList 快吗？', 'ArrayList 底层是动态数组\nLinkedList 底层是双向链表\nArrayList 随机访问快但中间操作要移动元素\nLinkedList 定位慢且节点内存开销更高', 'EASY', 'Java集合,List,数组链表', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 2, NOW(), NOW()),
('JAVA', 'synchronized 和 ReentrantLock 的区别', 'synchronized 和 ReentrantLock 有什么区别？', 'synchronized 是 JVM 内置锁，语法简单，进入和退出同步块时自动加锁释放锁。ReentrantLock 是 JUC 提供的显式锁，需要手动 unlock，但功能更灵活，支持可中断锁、公平锁和条件队列。实际选择时，普通互斥优先 synchronized，需要更强控制能力时再考虑 ReentrantLock。', '为什么 ReentrantLock 必须在 finally 中释放？\nsynchronized 锁的对象是什么？\n公平锁和非公平锁有什么区别？', 'synchronized 是 JVM 内置锁\nReentrantLock 是显式可重入锁\nReentrantLock 支持公平锁和可中断等待\n普通互斥优先 synchronized，需要高级能力再用 ReentrantLock', 'MEDIUM', 'Java并发,锁,JUC', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 3, NOW(), NOW()),
('JAVA', 'ThreadLocal 使用场景和风险', 'ThreadLocal 的使用场景和内存泄漏风险是什么？', 'ThreadLocal 用来给每个线程保存独立变量副本，常见场景是保存用户上下文、链路追踪 ID、数据库连接或事务上下文。它的数据实际挂在线程的 ThreadLocalMap 上。在线程池中线程会复用，如果使用后不 remove，可能导致旧数据串到新请求，也可能让 value 长时间无法释放。', 'ThreadLocalMap 的 key 为什么是弱引用？\n为什么线程池里使用 ThreadLocal 更容易出问题？\n如何规避 ThreadLocal 数据串用？', '每个线程保存独立变量副本\n数据存在线程的 ThreadLocalMap 中\n线程池复用线程会放大泄漏和串值风险\n使用后应在 finally 中 remove', 'MEDIUM', 'Java并发,ThreadLocal,内存泄漏', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 4, NOW(), NOW()),
('JVM', 'JVM 运行时内存区域', 'JVM 运行时内存区域有哪些？', 'JVM 运行时内存主要包括堆、方法区、虚拟机栈、本地方法栈和程序计数器。堆用于存放对象实例，是 GC 的重点区域；方法区存放类元数据、常量等；虚拟机栈保存方法调用栈帧；程序计数器记录当前线程执行位置。堆和方法区线程共享，栈和程序计数器线程私有。', '哪些区域是线程私有的？\n为什么程序计数器不会发生 OutOfMemoryError？\n堆和方法区分别主要存什么？', '堆主要存放对象实例\n方法区保存类元数据和常量\n虚拟机栈保存方法调用帧\n程序计数器和虚拟机栈是线程私有', 'EASY', 'JVM,内存区域,GC', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 101, NOW(), NOW()),
('JVM', 'CMS 和 G1 垃圾收集器区别', 'CMS 和 G1 垃圾收集器有什么区别？', 'CMS 以低停顿为目标，主要针对老年代，采用标记清除算法，可能产生内存碎片。G1 面向服务端大堆，把堆划分为多个 Region，通过预测停顿时间优先回收收益高的区域，并能同时管理新生代和老年代。G1 更适合需要可控停顿的大内存应用。', 'CMS 为什么会产生内存碎片？\nG1 的 Region 有什么作用？\n什么场景下更关注停顿时间？', 'CMS 主要目标是降低老年代回收停顿\nCMS 使用标记清除，容易产生碎片\nG1 将堆划分为 Region\nG1 可按预期停顿时间选择回收区域', 'HARD', 'JVM,垃圾收集器,CMS,G1', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 102, NOW(), NOW()),
('SPRING', 'Spring Bean 生命周期', 'Spring Bean 的生命周期是什么？', 'Spring Bean 生命周期大致包括实例化、属性填充、Aware 回调、BeanPostProcessor 前置处理、初始化方法、BeanPostProcessor 后置处理、使用以及销毁。面试中重点说明容器不只是创建对象，还负责依赖注入、扩展点调用和生命周期管理。很多框架能力都依赖 BeanPostProcessor 扩展。', 'BeanPostProcessor 通常用来做什么？\nInitializingBean 和 init-method 有什么区别？\n单例 Bean 和原型 Bean 的销毁阶段一样吗？', '实例化 Bean\n属性填充和依赖注入\nAware 和初始化回调\nBeanPostProcessor 提供重要扩展点\n容器负责单例 Bean 的销毁回调', 'MEDIUM', 'Spring,Bean,生命周期', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 201, NOW(), NOW()),
('SPRING', 'Spring AOP 实现原理', 'Spring AOP 的实现原理是什么？', 'Spring AOP 的核心是代理。容器为目标 Bean 创建代理对象，外部调用先进入代理，再在方法执行前后织入增强逻辑。目标类有接口时通常可用 JDK 动态代理，没有接口或需要代理类时可使用 CGLIB。AOP 常用于事务、日志、权限校验等横切逻辑。', 'JDK 动态代理和 CGLIB 有什么区别？\n为什么同类内部方法调用可能绕过 AOP？\nSpring 事务为什么依赖 AOP？', 'AOP 通过代理对象织入增强\nJDK 动态代理基于接口\nCGLIB 基于子类生成代理\n同类内部调用可能绕过代理\n适合日志、事务、权限等横切逻辑', 'MEDIUM', 'Spring,AOP,动态代理', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 202, NOW(), NOW()),
('SPRING', 'Spring 事务失效场景', 'Spring 事务失效的常见场景有哪些？', 'Spring 声明式事务依赖代理生效。常见失效场景包括同类内部方法调用、方法不是 public、异常被捕获没有继续抛出、默认只对 RuntimeException 回滚但抛了受检异常、对象没有交给 Spring 容器管理等。排查时要围绕代理是否生效和异常是否触发回滚两条线。', '为什么同类内部方法调用会导致事务失效？\n默认情况下 checked exception 会回滚吗？\n异常被 catch 后事务为什么可能提交？', '声明式事务依赖代理\n内部调用可能绕过代理\n默认回滚 RuntimeException\n异常被吞掉不会触发回滚\n非 Spring Bean 不受事务管理', 'HARD', 'Spring,事务,AOP', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 203, NOW(), NOW()),
('MYSQL', 'MySQL 索引失效场景及优化', '在什么情况下 MySQL 的索引会失效？请结合执行计划说明如何优化慢查询。', '索引失效常见原因包括违反最左前缀原则、隐式类型转换、在索引列上使用函数或运算、LIKE 以百分号开头、OR 条件包含无索引列等。优化时先看 EXPLAIN 的 type、key、rows、Extra，确认是否命中合适索引，再调整 SQL 写法或补充联合索引，尽量减少扫描行数和回表。', '什么是最左前缀原则？\nExplain 中 type、key、rows 分别怎么看？\n为什么索引列上使用函数可能导致索引失效？', '违反最左前缀原则\n隐式类型转换\n索引列上使用函数或运算\nLIKE 以百分号开头\n通过 EXPLAIN 判断索引命中情况', 'HARD', 'MySQL索引,B+树,SQL优化', '小林 coding, JavaGuide', 'https://xiaolincoding.com/interview/', 1, 301, NOW(), NOW()),
('MYSQL', 'InnoDB 使用 B+ 树索引的原因', 'InnoDB 为什么使用 B+ 树索引？', 'B+ 树适合磁盘存储和范围查询。它的非叶子节点主要保存键和指针，单个页能容纳更多索引项，因此树高较低，查询通常需要较少 IO。叶子节点按 key 有序并通过链表连接，范围查询可以顺序扫描。相比哈希索引，B+ 树更适合排序和范围条件。', 'B+ 树和 B 树有什么区别？\n为什么 B+ 树比二叉树更适合数据库索引？\n聚簇索引和二级索引在叶子节点存什么？', 'B+ 树树高低，减少磁盘 IO\n非叶子节点可容纳更多索引项\n叶子节点有序并适合范围查询\n比哈希索引更适合排序和范围条件', 'MEDIUM', 'MySQL索引,InnoDB,B+树', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 302, NOW(), NOW()),
('MYSQL', 'MVCC 机制', 'MVCC 是什么？解决了什么问题？', 'MVCC 是多版本并发控制，用多个历史版本减少读写阻塞。InnoDB 通过隐藏字段、undo log 和 Read View 判断当前事务能看到哪个版本。它让普通快照读不用加锁也能看到一致性视图，提高并发性能，并支撑可重复读等隔离级别。', 'Read View 里通常包含哪些信息？\n快照读和当前读有什么区别？\nMVCC 能完全替代锁吗？', 'MVCC 通过多版本减少读写冲突\nundo log 保存历史版本\nRead View 判断版本可见性\n快照读可不加锁读取一致性视图\n支撑可重复读隔离级别', 'HARD', 'MySQL事务,MVCC,隔离级别', '小林 coding, JavaGuide', 'https://xiaolincoding.com/interview/', 1, 303, NOW(), NOW()),
('REDIS', 'Redis 缓存击穿、穿透与雪崩', '请解释什么是缓存穿透、缓存击穿和缓存雪崩，并分别给出对应的工业级解决方案。', '缓存穿透是查询不存在的数据，缓存和数据库都没有，可用布隆过滤器、参数校验或缓存空值。缓存击穿是热点 key 过期后大量请求打到数据库，可用互斥锁、逻辑过期或热点预热。缓存雪崩是大量 key 同时过期或 Redis 故障，可用随机过期、限流降级和高可用部署。', '布隆过滤器为什么会有误判？\n热点 key 过期为什么不能让所有请求查数据库？\n随机过期时间解决的是什么问题？', '缓存穿透查询不存在数据\n缓存击穿针对热点 key 过期\n缓存雪崩是大量 key 同时失效\n布隆过滤器和缓存空值处理穿透\n互斥锁、逻辑过期、随机 TTL 降低数据库压力', 'MEDIUM', 'Redis缓存,高并发,缓存异常', '小林 coding, JavaGuide', 'https://xiaolincoding.com/interview/', 1, 401, NOW(), NOW()),
('REDIS', 'Redis 为什么快', 'Redis 为什么快？', 'Redis 快主要因为数据存储在内存中，避免了大部分磁盘 IO；核心命令执行采用单线程模型，减少线程切换和锁竞争；同时使用高效的数据结构和 IO 多路复用处理大量连接。需要注意，单线程指的是命令执行主流程，持久化、异步删除等任务可能由后台线程处理。', 'Redis 单线程为什么还能支持高并发？\nIO 多路复用解决了什么问题？\n哪些操作会让 Redis 变慢？', '数据主要在内存中读写\n命令执行主流程单线程避免锁竞争\nIO 多路复用处理大量连接\n高效数据结构降低操作成本\n慢命令和大 key 会影响性能', 'EASY', 'Redis,性能,IO多路复用', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 402, NOW(), NOW()),
('REDIS', 'Redis RDB 和 AOF 持久化', 'Redis 持久化 RDB 和 AOF 有什么区别？', 'RDB 是某个时间点的数据快照，文件紧凑、恢复快，但两次快照之间的数据可能丢失。AOF 记录写命令日志，数据安全性通常更好，但文件可能更大，恢复时需要重放命令。实际生产可结合两者，并通过 AOF 重写控制日志体积。', 'AOF 重写解决了什么问题？\nRDB 适合什么场景？\n如果 Redis 宕机，哪种方式通常丢数据更少？', 'RDB 是数据快照\nAOF 是写命令日志\nRDB 文件小且恢复快\nAOF 通常数据丢失更少\nAOF 重写用于压缩日志体积', 'MEDIUM', 'Redis持久化,RDB,AOF', '小林 coding, JavaGuide', 'https://javaguide.cn/home.html', 1, 403, NOW(), NOW());
